#include <stdlib.h>
#include <stdio.h>
#include <math.h>
#include <omp.h>
#include "backprop.h"

#define WIDTH 16
#define HEIGHT 16

extern void bpnn_layerforward(float *l1, float *l2, float **conn, int n1, int n2);
extern void bpnn_output_error(float *delta, float *target, float *output, int nj, float *err);
extern void bpnn_hidden_error(float *delta_h, int nh, float *delta_o, int no, float **who, float *hidden, float *err);
extern void bpnn_adjust_weights(float *delta, int ndelta, float *ly, int nly, float **w, float **oldw);

unsigned int num_threads = 0;
unsigned int num_blocks = 0;

static void bpnn_layerforward_omp(float *input_cuda,
                                  float *input_hidden_cuda,
                                  float *hidden_partial_sum,
                                  int in,
                                  int hid)
{
  int by, ty, tx, i;
  int max_blocks;

  max_blocks = in / HEIGHT;

  #pragma omp parallel for private(by, ty, tx, i) schedule(static)
  for (by = 0; by < max_blocks; by++) {
    float input_node[HEIGHT];
    float weight_matrix[HEIGHT][WIDTH];

    for (ty = 0; ty < HEIGHT; ty++) {
      int index_in = HEIGHT * by + ty + 1;
      input_node[ty] = input_cuda[index_in];
    }

    for (ty = 0; ty < HEIGHT; ty++) {
      for (tx = 0; tx < WIDTH; tx++) {
        int index = (hid + 1) * HEIGHT * by + (hid + 1) * ty + tx + 1 + (hid + 1);
        weight_matrix[ty][tx] = input_hidden_cuda[index] * input_node[ty];
      }
    }

    for (i = 1; i <= 4; i++) {
      int power_two = 1 << i;
      for (ty = 0; ty < HEIGHT; ty++) {
        if ((ty % power_two) == 0) {
          int other = ty + power_two / 2;
          for (tx = 0; tx < WIDTH; tx++) {
            weight_matrix[ty][tx] = weight_matrix[ty][tx] + weight_matrix[other][tx];
          }
        }
      }
    }

    for (ty = 0; ty < HEIGHT; ty++) {
      for (tx = 0; tx < WIDTH; tx++) {
        int index = (hid + 1) * HEIGHT * by + (hid + 1) * ty + tx + 1 + (hid + 1);
        input_hidden_cuda[index] = weight_matrix[ty][tx];
      }
    }

    for (ty = 0; ty < HEIGHT; ty++) {
      hidden_partial_sum[by * hid + ty] = weight_matrix[0][ty];
    }
  }
}

static void bpnn_adjust_weights_omp(float *delta,
                                    int hid,
                                    float *ly,
                                    int in,
                                    float *w,
                                    float *oldw)
{
  int by, ty, tx;
  int blocks;

  blocks = in / HEIGHT;

  #pragma omp parallel for collapse(3) private(by, ty, tx) schedule(static)
  for (by = 0; by < blocks; by++) {
    for (ty = 0; ty < HEIGHT; ty++) {
      for (tx = 0; tx < WIDTH; tx++) {
        int index = (hid + 1) * HEIGHT * by + (hid + 1) * ty + tx + 1 + (hid + 1);
        int index_y = HEIGHT * by + ty + 1;
        int index_x = tx + 1;
        float new_dw = (ETA * delta[index_x] * ly[index_y]) + (MOMENTUM * oldw[index]);
        w[index] += new_dw;
        oldw[index] = new_dw;
      }
    }
  }

  for (tx = 0; tx < WIDTH; tx++) {
    int index_x = tx + 1;
    float new_dw = (ETA * delta[index_x]) + (MOMENTUM * oldw[index_x]);
    w[index_x] += new_dw;
    oldw[index_x] = new_dw;
  }
}

void bpnn_train_cuda(BPNN *net, float *eo, float *eh)
{
  int in, hid, out;
  float out_err, hid_err;

  float *input_hidden_cuda;
  float *input_cuda;
  float *partial_sum;
  float *hidden_partial_sum;
  float *hidden_delta_cuda;
  float *input_prev_weights_cuda;
  float sum;
  float *input_weights_one_dim;
  float *input_weights_prev_one_dim;
  int m;
  int k, j;

  (void)eo;
  (void)eh;

  in = net->input_n;
  hid = net->hidden_n;
  out = net->output_n;

  m = 0;
  num_blocks = in / 16;

  input_weights_one_dim = (float *)malloc((in + 1) * (hid + 1) * sizeof(float));
  input_weights_prev_one_dim = (float *)malloc((in + 1) * (hid + 1) * sizeof(float));
  partial_sum = (float *)malloc(num_blocks * WIDTH * sizeof(float));
  hidden_partial_sum = (float *)malloc(num_blocks * WIDTH * sizeof(float));
