  input_hidden_cuda = (float *)malloc((in + 1) * (hid + 1) * sizeof(float));
  hidden_delta_cuda = (float *)malloc((hid + 1) * sizeof(float));
  input_prev_weights_cuda = (float *)malloc((in + 1) * (hid + 1) * sizeof(float));

  for (k = 0; k <= in; k++) {
    for (j = 0; j <= hid; j++) {
