                               float Rx,
                               float Ry,
                               float Rz,
                               float step) {
    float step_div_Cap = step / Cap;
    float Rx_1 = 1.0f / Rx;
    float Ry_1 = 1.0f / Ry;
    float Rz_1 = 1.0f / Rz;

    float *cur = temp_src;
    float *nxt = temp_dst;

    for (int it = 0; it < iteration; it++) {
#pragma omp parallel for collapse(2) schedule(static)
        for (int y = 0; y < grid_rows; y++) {
            for (int x = 0; x < grid_cols; x++) {
                int idx = y * grid_cols + x;

                int yN = (y == 0) ? 0 : (y - 1);
                int yS = (y == grid_rows - 1) ? (grid_rows - 1) : (y + 1);
                int xW = (x == 0) ? 0 : (x - 1);
                int xE = (x == grid_cols - 1) ? (grid_cols - 1) : (x + 1);

                int idxN = yN * grid_cols + x;
                int idxS = yS * grid_cols + x;
                int idxW = y * grid_cols + xW;
                int idxE = y * grid_cols + xE;

                nxt[idx] = cur[idx] + step_div_Cap *
                                        (power[idx] +
                                         (cur[idxS] + cur[idxN] - 2.0f * cur[idx]) * Ry_1 +
                                         (cur[idxE] + cur[idxW] - 2.0f * cur[idx]) * Rx_1 +
                                         (amb_temp - cur[idx]) * Rz_1);
            }
        }

        if (it != iteration - 1) {
            float *tmp = cur;
            cur = nxt;
            nxt = tmp;
        }
    }

    if ((iteration % 2) == 0) {
        memcpy(temp_dst, temp_src, sizeof(float) * (size_t)grid_cols * (size_t)grid_rows);
    }
}

int compute_tran_temp(float *MatrixPower, float *MatrixTemp[2], int col, int row,
                      int total_iterations, int num_iterations, int blockCols, int blockRows, int borderCols, int borderRows) {
    (void)blockCols;
    (void)blockRows;
    (void)borderCols;
    (void)borderRows;

    float grid_height = chip_height / row;
    float grid_width = chip_width / col;

    float Cap = FACTOR_CHIP * SPEC_HEAT_SI * t_chip * grid_width * grid_height;
    float Rx = grid_width / (2.0f * K_SI * t_chip * grid_height);
    float Ry = grid_height / (2.0f * K_SI * t_chip * grid_width);
    float Rz = t_chip / (K_SI * grid_height * grid_width);

    float max_slope = MAX_PD / (FACTOR_CHIP * t_chip * SPEC_HEAT_SI);
    float step = PRECISION / max_slope;
    float t;
    float time_elapsed;
    time_elapsed = 0.001f;
    (void)time_elapsed;

    int src = 1, dst = 0;

    for (t = 0; t < total_iterations; t += num_iterations) {
        int temp = src;
        src = dst;
        dst = temp;

        int iter = MIN(num_iterations, total_iterations - (int)t);
        calculate_temp_cpu(iter, MatrixPower, MatrixTemp[src], MatrixTemp[dst], col, row, Cap, Rx, Ry, Rz, step);
    }
    return dst;
}

