#define BLOCK_SIZE 16
#define STR_SIZE 256

#define block_x_ 128
#define block_y_ 2
#define block_z_ 1
#define MAX_PD (3.0e6)

#define PRECISION 0.001
#define SPEC_HEAT_SI 1.75e6
#define K_SI 100

#define FACTOR_CHIP 0.5

float t_chip = 0.0005;
float chip_height = 0.016;
float chip_width = 0.016;
float amb_temp = 80.0f;

long long get_time() {
    struct timeval tv;
    gettimeofday(&tv, NULL);
    return (tv.tv_sec * 1000000LL) + tv.tv_usec;
}

void fatal(const char *s)
{
    fprintf(stderr, "Error: %s\n", s);
}

void readinput(float *vect, int grid_rows, int grid_cols, int layers, char *file) {
    int i,j,k;
    FILE *fp;
    char str[STR_SIZE];
    float val;

    if( (fp  = fopen(file, "r" )) == 0 )
      fatal( "The file was not opened" );

    for (i=0; i <= grid_rows-1; i++)
      for (j=0; j <= grid_cols-1; j++)
        for (k=0; k <= layers-1; k++)
          {
            if (fgets(str, STR_SIZE, fp) == NULL) fatal("Error reading file\n");
            if (feof(fp))
              fatal("not enough lines in file");
            if ((sscanf(str, "%f", &val) != 1))
              fatal("invalid file format");
            vect[i*grid_cols+j+k*grid_rows*grid_cols] = val;
          }

    fclose(fp);
}

void writeoutput(float *vect, int grid_rows, int grid_cols, int layers, char *file) {
    int i,j,k, index=0;
    FILE *fp;
    char str[STR_SIZE];

    if( (fp = fopen(file, "w" )) == 0 )
      printf( "The file was not opened\n" );

    for (i=0; i < grid_rows; i++)
      for (j=0; j < grid_cols; j++)
        for (k=0; k < layers; k++)
          {
            sprintf(str, "%d\t%g\n", index, vect[i*grid_cols+j+k*grid_rows*grid_cols]);
            fputs(str,fp);
            index++;
          }

    fclose(fp);
}

void computeTempCPU(float *pIn, float* tIn, float *tOut,
        int nx, int ny, int nz, float Cap,
        float Rx, float Ry, float Rz,
        float dt, int numiter)
{
    float ce, cw, cn, cs, ct, cb, cc;
    float stepDivCap = dt / Cap;
    ce = cw = stepDivCap / Rx;
    cn = cs = stepDivCap / Ry;
    ct = cb = stepDivCap / Rz;

    cc = 1.0f - (2.0f*ce + 2.0f*cn + 3.0f*ct);

    int c,w,e,n,s,b,t;
    int x,y,z;
    int i = 0;
    do{
        for(z = 0; z < nz; z++)
            for(y = 0; y < ny; y++)
                for(x = 0; x < nx; x++)
                {
                    c = x + y * nx + z * nx * ny;

                    w = (x == 0) ? c      : c - 1;
                    e = (x == nx - 1) ? c : c + 1;
                    n = (y == 0) ? c      : c - nx;
                    s = (y == ny - 1) ? c : c + nx;
                    b = (z == 0) ? c      : c - nx * ny;
                    t = (z == nz - 1) ? c : c + nx * ny;

                    tOut[c] = tIn[c]*cc + tIn[n]*cn + tIn[s]*cs + tIn[e]*ce + tIn[w]*cw + tIn[t]*ct + tIn[b]*cb + (dt/Cap) * pIn[c] + ct*amb_temp;
                }
        {
            float *temp = tIn;
            tIn = tOut;
            tOut = temp;
        }
        i++;
    }
    while(i < numiter);
}

static void hotspotOpt1_kernel(float *p, float* tIn, float *tOut, float sdc,
        int nx, int ny, int nz,
        float ce, float cw,
        float cn, float cs,
        float ct, float cb,
        float cc)
{
    int grid_x = nx / 64;
    int grid_y = ny / 4;
    int max_i = grid_x * 64;
    int max_j = grid_y * 4;
    int xy = nx * ny;
    float amb = 80.0f;

    #pragma omp parallel for collapse(2) schedule(static)
    for (int j = 0; j < max_j; ++j) {
        for (int i = 0; i < max_i; ++i) {
            int c = i + j * nx;

            int W = (i == 0)    ? c : c - 1;
            int E = (i == nx-1) ? c : c + 1;
            int N = (j == 0)    ? c : c - nx;
            int S = (j == ny-1) ? c : c + nx;

            float temp1, temp2, temp3;
            temp1 = temp2 = tIn[c];
            temp3 = tIn[c + xy];
            tOut[c] = cc * temp2 + cw * tIn[W] + ce * tIn[E] + cs * tIn[S]
                    + cn * tIn[N] + cb * temp1 + ct * temp3 + sdc * p[c] + ct * amb;
            c += xy;
            W += xy;
            E += xy;
            N += xy;
            S += xy;

            for (int k = 1; k < nz - 1; ++k) {
                temp1 = temp2;
                temp2 = temp3;
                temp3 = tIn[c + xy];
                tOut[c] = cc * temp2 + cw * tIn[W] + ce * tIn[E] + cs * tIn[S]
                        + cn * tIn[N] + cb * temp1 + ct * temp3 + sdc * p[c] + ct * amb;
                c += xy;
                W += xy;
                E += xy;
                N += xy;
                S += xy;
            }

            temp1 = temp2;
            temp2 = temp3;
            tOut[c] = cc * temp2 + cw * tIn[W] + ce * tIn[E] + cs * tIn[S]
                    + cn * tIn[N] + cb * temp1 + ct * temp3 + sdc * p[c] + ct * amb;
        }
    }
}

