	static const fp b12_9 = 3.0f / 41.0f;
	static const fp b12_10 = 6.0f / 41.0f;
	static const fp b13_1 = -1777.0f / 4100.0f;
	static const fp b13_4 = -341.0f / 164.0f;
	static const fp b13_5 = 4496.0f / 1025.0f;
	static const fp b13_6 = -289.0f / 82.0f;
	static const fp b13_7 = 2193.0f / 4100.0f;
	static const fp b13_8 = 51.0f / 82.0f;
	static const fp b13_9 = 33.0f / 164.0f;
	static const fp b13_10 = 12.0f / 41.0f;

	static const fp err_factor  = -41.0f / 840.0f;

	fp h2_7 = a2 * h;

	fp timeinst_temp;
	fp* initvalu_temp;
	fp** finavalu_temp;

	int i;

	initvalu_temp= (fp *) malloc(EQUATIONS* sizeof(fp));
	finavalu_temp= (fp **) malloc(13* sizeof(fp *));
	for (i= 0; i<13; i++){
		finavalu_temp[i]= (fp *) malloc(EQUATIONS* sizeof(fp));
	}

	timeinst_temp = timeinst;
	for(i=0; i<EQUATIONS; i++){
		initvalu_temp[i] = initvalu[i] ;
	}
	master(timeinst_temp, initvalu_temp, parameter, finavalu_temp[0], com, d_initvalu, d_finavalu, d_params, d_com);

	timeinst_temp = timeinst+h2_7;
	for(i=0; i<EQUATIONS; i++){
		initvalu_temp[i] = initvalu[i] + h2_7 * (finavalu_temp[0][i]);
	}
	master(timeinst_temp, initvalu_temp, parameter, finavalu_temp[1], com, d_initvalu, d_finavalu, d_params, d_com);

	timeinst_temp = timeinst+a3*h;
	for(i=0; i<EQUATIONS; i++){
		initvalu_temp[i] = initvalu[i] + h * ( b31*finavalu_temp[0][i] + b32*finavalu_temp[1][i]);
	}
	master(timeinst_temp, initvalu_temp, parameter, finavalu_temp[2], com, d_initvalu, d_finavalu, d_params, d_com);

	timeinst_temp = timeinst+a4*h;
	for(i=0; i<EQUATIONS; i++){
		initvalu_temp[i] = initvalu[i] + h * ( b41*finavalu_temp[0][i] + b43*finavalu_temp[2][i]) ;
	}
	master(timeinst_temp, initvalu_temp, parameter, finavalu_temp[3], com, d_initvalu, d_finavalu, d_params, d_com);

	timeinst_temp = timeinst+a5*h;
	for(i=0; i<EQUATIONS; i++){
		initvalu_temp[i] = initvalu[i] + h * ( b51*finavalu_temp[0][i] + b53*finavalu_temp[2][i] + b54*finavalu_temp[3][i]) ;
	}
	master(timeinst_temp, initvalu_temp, parameter, finavalu_temp[4], com, d_initvalu, d_finavalu, d_params, d_com);

	timeinst_temp = timeinst+a6*h;
	for(i=0; i<EQUATIONS; i++){
		initvalu_temp[i] = initvalu[i] + h * ( b61*finavalu_temp[0][i] + b64*finavalu_temp[3][i] + b65*finavalu_temp[4][i]) ;
	}
	master(timeinst_temp, initvalu_temp, parameter, finavalu_temp[5], com, d_initvalu, d_finavalu, d_params, d_com);

	timeinst_temp = timeinst+a7*h;
	for(i=0; i<EQUATIONS; i++){
		initvalu_temp[i] = initvalu[i] + h * ( b71*finavalu_temp[0][i] + b74*finavalu_temp[3][i] + b75*finavalu_temp[4][i] + b76*finavalu_temp[5][i]);
	}
	master(timeinst_temp, initvalu_temp, parameter, finavalu_temp[6], com, d_initvalu, d_finavalu, d_params, d_com);

	timeinst_temp = timeinst+a8*h;
	for(i=0; i<EQUATIONS; i++){
		initvalu_temp[i] = initvalu[i] + h * ( b81*finavalu_temp[0][i] + b85*finavalu_temp[4][i] + b86*finavalu_temp[5][i] + b87*finavalu_temp[6][i]);
	}
	master(timeinst_temp, initvalu_temp, parameter, finavalu_temp[7], com, d_initvalu, d_finavalu, d_params, d_com);

	timeinst_temp = timeinst+a9*h;
	for(i=0; i<EQUATIONS; i++){
		initvalu_temp[i] = initvalu[i] + h * ( b91*finavalu_temp[0][i] + b94*finavalu_temp[3][i] + b95*finavalu_temp[4][i] + b96*finavalu_temp[5][i] + b97*finavalu_temp[6][i]+ b98*finavalu_temp[7][i]) ;
	}
	master(timeinst_temp, initvalu_temp, parameter, finavalu_temp[8], com, d_initvalu, d_finavalu, d_params, d_com);

	timeinst_temp = timeinst+a10*h;
	for(i=0; i<EQUATIONS; i++){
		initvalu_temp[i] = initvalu[i] + h * ( b10_1*finavalu_temp[0][i] + b10_4*finavalu_temp[3][i] + b10_5*finavalu_temp[4][i] + b10_6*finavalu_temp[5][i] + b10_7*finavalu_temp[6][i] + b10_8*finavalu_temp[7][i] + b10_9*finavalu_temp[8] [i]) ;
	}
	master(timeinst_temp, initvalu_temp, parameter, finavalu_temp[9], com, d_initvalu, d_finavalu, d_params, d_com);

	timeinst_temp = timeinst+h;
	for(i=0; i<EQUATIONS; i++){
		initvalu_temp[i] = initvalu[i] + h * ( b11_1*finavalu_temp[0][i] + b11_4*finavalu_temp[3][i] + b11_5*finavalu_temp[4][i] + b11_6*finavalu_temp[5][i] + b11_7*finavalu_temp[6][i] + b11_8*finavalu_temp[7][i] + b11_9*finavalu_temp[8][i]+ b11_10 * finavalu_temp[9][i]);
	}
	master(timeinst_temp, initvalu_temp, parameter, finavalu_temp[10], com, d_initvalu, d_finavalu, d_params, d_com);

	timeinst_temp = timeinst;
	for(i=0; i<EQUATIONS; i++){
		initvalu_temp[i] = initvalu[i] + h * ( b12_1*finavalu_temp[0][i] + b12_6*finavalu_temp[5][i] + b12_7*finavalu_temp[6][i] + b12_8*finavalu_temp[7][i] + b12_9*finavalu_temp[8][i] + b12_10 * finavalu_temp[9][i]) ;
	}
	master(timeinst_temp, initvalu_temp, parameter, finavalu_temp[11], com, d_initvalu, d_finavalu, d_params, d_com);

	timeinst_temp = timeinst+h;
	for(i=0; i<EQUATIONS; i++){
		initvalu_temp[i] = initvalu[i] + h * ( b13_1*finavalu_temp[0][i] + b13_4*finavalu_temp[3][i] + b13_5*finavalu_temp[4][i] + b13_6*finavalu_temp[5][i] + b13_7*finavalu_temp[6][i] + b13_8*finavalu_temp[7][i] + b13_9*finavalu_temp[8][i] + b13_10*finavalu_temp[9][i] + finavalu_temp[11][i]) ;
	}
	master(timeinst_temp, initvalu_temp, parameter, finavalu_temp[12], com, d_initvalu, d_finavalu, d_params, d_com);

	for(i=0; i<EQUATIONS; i++){
		finavalu[i]= initvalu[i] +  h * (c_1_11 * (finavalu_temp[0][i] + finavalu_temp[10][i])  + c6 * finavalu_temp[5][i] + c_7_8 * (finavalu_temp[6][i] + finavalu_temp[7][i]) + c_9_10 * (finavalu_temp[8][i] + finavalu_temp[9][i]) );
	}

	for(i=0; i<EQUATIONS; i++){
		error[i] = fabsf(err_factor * (finavalu_temp[0][i] + finavalu_temp[10][i] - finavalu_temp[11][i] - finavalu_temp[12][i]));
	}

	for (i = 0; i < 13; i++) free(finavalu_temp[i]);
	free(initvalu_temp);
	free(finavalu_temp);
}

int solver(	fp** y,
					fp* x,
					int xmax,
					fp* params,
					fp* com,

					fp* d_initvalu,
					fp* d_finavalu,
					fp* d_params,
					fp* d_com) {

	fp err_exponent;
	int error;
	int outside;
	fp h;
	fp h_init;
	fp tolerance;
	int xmin;

	fp scale_min;
	fp scale_fina;
	fp* err= (fp *) malloc(EQUATIONS* sizeof(fp));
	fp* scale= (fp *) malloc(EQUATIONS* sizeof(fp));
	fp* yy= (fp *) malloc(EQUATIONS* sizeof(fp));

	int i, j, k;

	err_exponent = 1.0f / 7.0f;
	h_init = 1;
	h = h_init;
	xmin = 0;
	tolerance = 10 / (fp)(xmax-xmin);

	x[0] = 0;

	if (xmax < xmin || h <= 0.0){
		free(err); free(scale); free(yy);
		return -2;
	}
	if (xmax == xmin){
		free(err); free(scale); free(yy);
		return 0;
	}
	if (h > (xmax - xmin) ) {
		h = (fp)xmax - (fp)xmin;
	}

	for(k=1; k<=xmax; k++) {
		x[k] = k-1;
		h = h_init;
		scale_fina = 1.0f;

		for (j = 0; j < ATTEMPTS; j++) {
			error = 0;
			outside = 0;
			scale_min = MAX_SCALE_FACTOR;

			embedded_fehlberg_7_8(x[k], h, y[k-1], y[k], err, params, com, d_initvalu, d_finavalu, d_params, d_com);

			for(i=0; i<EQUATIONS; i++){
				if(err[i] > 0){
					error = 1;
				}
			}
			if (error != 1) {
				scale_fina = MAX_SCALE_FACTOR;
				break;
			}

			for(i=0; i<EQUATIONS; i++){
				if(y[k-1][i] == 0.0f){
					yy[i] = tolerance;
				}
				else{
					yy[i] = fabsf(y[k-1][i]);
				}
				scale[i] = 0.8f * powf( tolerance * yy[i] / err[i] , err_exponent );
				if(scale[i]<scale_min){
					scale_min = scale[i];
				}
			}
			scale_fina = min( max(scale_min,MIN_SCALE_FACTOR), MAX_SCALE_FACTOR);

			for(i=0; i<EQUATIONS; i++){
				if ( err[i] > ( tolerance * yy[i] ) ){
					outside = 1;
				}
			}
			if (outside == 0){
				break;
			}

			h = h * scale_fina;

			if (h >= 0.9f) {
				h = 0.9f;
			}
			if ( x[k] + h > (fp)xmax ){
				h = (fp)xmax - x[k];
			}
			else if ( x[k] + h + 0.5f * h > (fp)xmax ){
				h = 0.5f * h;
			}
		}

		x[k] = x[k] + h;

		if ( j >= ATTEMPTS ) {
			free(err); free(scale); free(yy);
			return -1;
		}
	}

	free(err);
	free(scale);
	free(yy);
	return 0;
}

int work(int xmax, int workload){

	long long time0, time1, time2, time3, time4, time5;
	time0 = get_time();

	long long memory;
	int i,j;
	int status;

	fp*** y;
	fp** x;
	fp** params;
	fp* com;

	time1 = get_time();

	memory = workload*(xmax+1)*EQUATIONS*4;
	if(memory>1000000000){
		printf("ERROR: trying to allocate more than 1.0GB of memory, decrease workload and span parameters or change memory parameter\n");
		return 0;
	}

	y = (fp ***) malloc(workload* sizeof(fp **));
	for(i=0; i<workload; i++){
		y[i] = (fp**)malloc((1+xmax)*sizeof(fp*));
		for(j=0; j<(1+xmax); j++){
			y[i][j]= (fp *) malloc(EQUATIONS* sizeof(fp));
		}
	}

	x = (fp **) malloc(workload * sizeof(fp *));
	for (i= 0; i<workload; i++){
		x[i]= (fp *)malloc((1+xmax) *sizeof(fp));
	}

	params = (fp **) malloc(workload * sizeof(fp *));
	for (i= 0; i<workload; i++){
		params[i]= (fp *)malloc(PARAMETERS * sizeof(fp));
	}

	com = (fp*)malloc(3 * sizeof(fp));

	fp* d_initvalu = (fp*)malloc(EQUATIONS * sizeof(fp));
	fp* d_finavalu = (fp*)malloc(EQUATIONS * sizeof(fp));
	fp* d_params = (fp*)malloc(PARAMETERS * sizeof(fp));
	fp* d_com = (fp*)malloc(3 * sizeof(fp));

	time2 = get_time();

	for(i=0; i<workload; i++){
		read("../../data/myocyte/y.txt", y[i][0], EQUATIONS, 1, 0);
	}
	for(i=0; i<workload; i++){
		read("../../data/myocyte/params.txt", params[i], PARAMETERS, 1, 0);
	}

	time3 = get_time();

	for(i=0; i<workload; i++){
		status = solver(y[i], x[i], xmax, params[i], com, d_initvalu, d_finavalu, d_params, d_com);
		if(status !=0){
			printf("STATUS: %d\n", status);
		}
	}

	FILE * pFile;
	pFile = fopen ("output.txt","w");
	if (pFile==NULL){
		fputs ("fopen example",pFile);
		return -1;
	}
	for(i=0; i<workload; i++){
		fprintf(pFile, "WORKLOAD %d:\n", i);
		for(j=0; j<(xmax+1); j++){
			int k;
			fprintf(pFile, "\tTIME %d:\n", j);
			for(k=0; k<EQUATIONS; k++){
				fprintf(pFile, "\t\ty[%d][%d][%d]=%10.7e\n", i, j, k, y[i][j][k]);
			}
		}
	}
	fclose (pFile);

	time4 = get_time();

	for (i= 0; i< workload; i++){
		for (j= 0; j< (1+xmax); j++){
			free(y[i][j]);
		}
		free(y[i]);
	}
	free(y);

	for (i= 0; i< workload; i++){
		free(x[i]);
	}
	free(x);

	for (i= 0; i< workload; i++){
		free(params[i]);
	}
	free(params);

	time5= get_time();

	free(com);
	free(d_initvalu);
	free(d_finavalu);
	free(d_params);
	free(d_com);

	printf("Time spent in different stages of the application:\n");
	printf("%.12f s, %.12f % : SETUP VARIABLES\n", (float) (time1-time0) / 1000000, (float) (time1-time0) / (float) (time5-time0) * 100);
	printf("%.12f s, %.12f % : ALLOCATE CPU MEMORY AND GPU MEMORY\n", (float) (time2-time1) / 1000000, (float) (time2-time1) / (float) (time5-time0) * 100);
	printf("%.12f s, %.12f % : READ DATA FROM FILES\n", (float) (time3-time2) / 1000000, (float) (time3-time2) / (float) (time5-time0) * 100);
	printf("%.12f s, %.12f % : RUN COMPUTATION\n", (float) (time4-time3) / 1000000, (float) (time4-time3) / (float) (time5-time0) * 100);
	printf("%.12f s, %.12f % : FREE MEMORY\n", (float) (time5-time4) / 1000000, (float) (time5-time4) / (float) (time5-time0) * 100);
	printf("Total time:\n");
	printf("%.12f s\n", (float) (time5-time0) / 1000000);

	return 0;
}

static void kernel_fin(fp *initvalu,
							int initvalu_offset_ecc,
							int initvalu_offset_Dyad,
							int initvalu_offset_SL,
							int initvalu_offset_Cyt,
							fp *parameter,
							fp *finavalu,
							fp JCaDyad,
							fp JCaSL,
							fp JCaCyt){

	fp BtotDyad;
	fp CaMKIItotDyad;

	fp Vmyo;
	fp Vdyad;
	fp VSL;

	fp kSLmyo;
	fp k0Boff;
	fp k0Bon;
	fp k2Boff;
	fp k2Bon;
	fp k4Bon;
	fp CaMtotDyad;
	fp Bdyad;
	fp J_cam_dyadSL;
	fp J_ca2cam_dyadSL;
	fp J_ca4cam_dyadSL;
	fp J_cam_SLmyo;
	fp J_ca2cam_SLmyo;
	fp J_ca4cam_SLmyo;

	BtotDyad      = parameter[2];
	CaMKIItotDyad = parameter[3];

	Vmyo = 2.1454e-11f;
	Vdyad = 1.7790e-14f;
	VSL = 6.6013e-13f;

	kSLmyo = 8.587e-15f;
	k0Boff = 0.0014f;
	k0Bon = k0Boff/0.2f;
	k2Boff = k0Boff/100.0f;
	k2Bon = k0Bon;
	k4Bon = k0Bon;

	finavalu[initvalu_offset_ecc+35] = finavalu[initvalu_offset_ecc+35] + 1e-3f*JCaDyad;
	finavalu[initvalu_offset_ecc+36] = finavalu[initvalu_offset_ecc+36] + 1e-3f*JCaSL;
	finavalu[initvalu_offset_ecc+37] = finavalu[initvalu_offset_ecc+37] + 1e-3f*JCaCyt;

	CaMtotDyad = initvalu[initvalu_offset_Dyad+0]
			   + initvalu[initvalu_offset_Dyad+1]
			   + initvalu[initvalu_offset_Dyad+2]
			   + initvalu[initvalu_offset_Dyad+3]
			   + initvalu[initvalu_offset_Dyad+4]
			   + initvalu[initvalu_offset_Dyad+5]
			   + CaMKIItotDyad * (  initvalu[initvalu_offset_Dyad+6]
								  + initvalu[initvalu_offset_Dyad+7]
								  + initvalu[initvalu_offset_Dyad+8]
								  + initvalu[initvalu_offset_Dyad+9])
			   + initvalu[initvalu_offset_Dyad+12]
			   + initvalu[initvalu_offset_Dyad+13]
			   + initvalu[initvalu_offset_Dyad+14];
	Bdyad = BtotDyad - CaMtotDyad;
	J_cam_dyadSL = 1e-3f * (  k0Boff*initvalu[initvalu_offset_Dyad+0] - k0Bon*Bdyad*initvalu[initvalu_offset_SL+0]);
	J_ca2cam_dyadSL = 1e-3f * (  k2Boff*initvalu[initvalu_offset_Dyad+1] - k2Bon*Bdyad*initvalu[initvalu_offset_SL+1]);
	J_ca4cam_dyadSL = 1e-3f * (  k2Boff*initvalu[initvalu_offset_Dyad+2] - k4Bon*Bdyad*initvalu[initvalu_offset_SL+2]);

	J_cam_SLmyo = kSLmyo * (  initvalu[initvalu_offset_SL+0] - initvalu[initvalu_offset_Cyt+0]);
	J_ca2cam_SLmyo = kSLmyo * (  initvalu[initvalu_offset_SL+1] - initvalu[initvalu_offset_Cyt+1]);
	J_ca4cam_SLmyo = kSLmyo * (  initvalu[initvalu_offset_SL+2] - initvalu[initvalu_offset_Cyt+2]);

	finavalu[initvalu_offset_Dyad+0] = finavalu[initvalu_offset_Dyad+0] - J_cam_dyadSL;
	finavalu[initvalu_offset_Dyad+1] = finavalu[initvalu_offset_Dyad+1] - J_ca2cam_dyadSL;
	finavalu[initvalu_offset_Dyad+2] = finavalu[initvalu_offset_Dyad+2] - J_ca4cam_dyadSL;

	finavalu[initvalu_offset_SL+0] = finavalu[initvalu_offset_SL+0] + J_cam_dyadSL*Vdyad/VSL - J_cam_SLmyo/VSL;
	finavalu[initvalu_offset_SL+1] = finavalu[initvalu_offset_SL+1] + J_ca2cam_dyadSL*Vdyad/VSL - J_ca2cam_SLmyo/VSL;
	finavalu[initvalu_offset_SL+2] = finavalu[initvalu_offset_SL+2] + J_ca4cam_dyadSL*Vdyad/VSL - J_ca4cam_SLmyo/VSL;

	finavalu[initvalu_offset_Cyt+0] = finavalu[initvalu_offset_Cyt+0] + J_cam_SLmyo/Vmyo;
	finavalu[initvalu_offset_Cyt+1] = finavalu[initvalu_offset_Cyt+1] + J_ca2cam_SLmyo/Vmyo;
	finavalu[initvalu_offset_Cyt+2] = finavalu[initvalu_offset_Cyt+2] + J_ca4cam_SLmyo/Vmyo;
}

