	fp dCaM, dCa2CaM, dCa4CaM, dCaMB, dCa2CaMB, dCa4CaMB;
	fp dPb2, dPb, dPt, dPt2, dPa;
	fp dCa4CaN, dCaMCa4CaN, dCa2CaMCa4CaN, dCa4CaMCa4CaN;

