static void srad_cuda_1_omp(
    float *E_C,
    float *W_C,
    float *N_C,
    float *S_C,
    float *J_cuda,
    float *C_cuda,
    int cols,
    int rows,
    float q0sqr) {
#pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            int index = i * cols + j;

            int in = (i == 0) ? 0 : (i - 1);
            int is = (i == rows - 1) ? (rows - 1) : (i + 1);
            int jw = (j == 0) ? 0 : (j - 1);
            int je = (j == cols - 1) ? (cols - 1) : (j + 1);

            float jc = J_cuda[index];
            float n = J_cuda[in * cols + j] - jc;
            float s = J_cuda[is * cols + j] - jc;
            float w = J_cuda[i * cols + jw] - jc;
            float e = J_cuda[i * cols + je] - jc;

            float g2 = (n * n + s * s + w * w + e * e) / (jc * jc);
            float l = (n + s + w + e) / jc;
            float num = (0.5f * g2) - ((1.0f / 16.0f) * (l * l));
            float den = 1.0f + (0.25f * l);
            float qsqr = num / (den * den);

            den = (qsqr - q0sqr) / (q0sqr * (1.0f + q0sqr));
            float c = 1.0f / (1.0f + den);

            if (c < 0.0f) c = 0.0f;
            else if (c > 1.0f) c = 1.0f;

            C_cuda[index] = c;
            E_C[index] = e;
            W_C[index] = w;
            S_C[index] = s;
            N_C[index] = n;
        }
    }
}

static void srad_cuda_2_omp(
    float *E_C,
    float *W_C,
    float *N_C,
    float *S_C,
    float *J_cuda,
    float *C_cuda,
    int cols,
    int rows,
    float lambda,
    float q0sqr) {
    (void)q0sqr;
#pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            int index = i * cols + j;
            int is = (i == rows - 1) ? (rows - 1) : (i + 1);
            int je = (j == cols - 1) ? (cols - 1) : (j + 1);

            float cc = C_cuda[index];
            float cn = cc;
            float cs = C_cuda[is * cols + j];
            float cw = cc;
            float ce = C_cuda[i * cols + je];

            float d_sum = cn * N_C[index] + cs * S_C[index] + cw * W_C[index] + ce * E_C[index];
            J_cuda[index] = J_cuda[index] + 0.25f * lambda * d_sum;
        }
    }
}

