#ifdef INSERT_WASTE
float waste(float s) {
  for (int i = 0; i < 4; i++) {
    s += pow(s, 0.78);
  }
  return s;
}
#endif

float dist(Point p1, Point p2, int dim) {
  int i;
  float result = 0.0;
  for (i = 0; i < dim; i++)
    result += (p1.coord[i] - p2.coord[i]) * (p1.coord[i] - p2.coord[i]);
#ifdef INSERT_WASTE
  float s = waste(result);
  result += s;
  result -= s;
#endif
  return result;
}

static inline float d_dist(int p1, int p2, int num, int dim, float *coord_arr) {
  float retval = 0.0f;
  for (int i = 0; i < dim; i++) {
    float tmp = coord_arr[(i * num) + p1] - coord_arr[(i * num) + p2];
    retval += tmp * tmp;
  }
  return retval;
}

